// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string; title?: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




export default function Component(props: Props) {
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  // Local state management
  const [tasks, setTasks] = useState<typeof props.tasks>(() => props.tasks || []);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState<string>('');
  const [expandedAddForm, setExpandedAddForm] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState<string>('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const toDoColumnId = props.columns?.find(c => c.name?.toLowerCase().includes('to do'))?.id || 'todo';

  // Sync tasks from props
  useEffect(() => {
    setTasks(props.tasks || []);
  }, [props.tasks]);

  // Sync stream updates from other team members
  useEffect(() => {
    if (taskChanged.latest) {
      const { action, task } = taskChanged.latest;
      if (action === 'move' || action === 'edit' || action === 'create') {
        setTasks(prev => {
          const idx = prev.findIndex(t => t.id === task?.id);
          if (idx >= 0) {
            const updated = [...prev];
            updated[idx] = task || updated[idx];
            return updated;
          }
          return task ? [...prev, task] : prev;
        });
      } else if (action === 'delete') {
        setTasks(prev => prev.filter(t => t.id !== task?.id));
      }
    }
  }, [taskChanged.latest]);

  // Handlers
  const handleMoveTask = useCallback((taskId: string, targetColumn: string) => {
    setTasks(prev => prev.map(t =>
      t.id === taskId ? { ...t, column: targetColumn } : t
    ));
    taskUpdate({ action: 'move', taskId, data: { column: targetColumn } });
  }, [taskUpdate]);

  const handleEditTask = useCallback((taskId: string, newTitle: string) => {
    setTasks(prev => prev.map(t =>
      t.id === taskId ? { ...t, title: newTitle } : t
    ));
    taskUpdate({ action: 'edit', taskId, data: { column: tasks.find(t => t.id === taskId)?.column || 'todo', title: newTitle } });
    setEditingTaskId(null);
    setEditingTitle('');
  }, [taskUpdate, tasks]);

  const handleCreateTask = useCallback(() => {
    if (newTaskTitle.trim()) {
      const newTask = {
        id: `task-${Date.now()}`,
        title: newTaskTitle,
        priority: newTaskPriority,
        assignee: '',
        column: toDoColumnId,
        dueDate: '',
      };
      setTasks(prev => [...prev, newTask]);
      taskUpdate({ action: 'create', taskId: newTask.id, data: { column: toDoColumnId } });
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setExpandedAddForm(null);
    }
  }, [newTaskTitle, newTaskPriority, taskUpdate, toDoColumnId]);

  // Compute statistics and tasks per column
  const totalTasks = tasks.length;
  const completedTasks = tasks.filter(t => t.column === 'done').length;
  const tasksPerColumn = useMemo(() => {
    const groups: Record<string, typeof tasks> = {};
    props.columns?.forEach(col => {
      groups[col.id || ''] = [];
    });
    tasks.forEach(task => {
      const col = task.column || 'todo';
      if (!groups[col]) groups[col] = [];
      groups[col].push(task);
    });
    return groups;
  }, [tasks, props.columns]);

  // Priority color mapping
  const getPriorityVariant = (priority?: string) => {
    switch (priority) {
      case 'high': return 'error' as const;
      case 'medium': return 'warning' as const;
      case 'low': return 'success' as const;
      default: return 'default' as const;
    }
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Summary Bar */}
        <Box background="var(--ggui-color-primary-50)" padding="var(--ggui-spacing-4)" borderRadius="var(--ggui-shape-radius-lg)">
          <Row justify="between" align="center">
            <Stack direction="horizontal" gap="var(--ggui-spacing-4)" align="center">
              <Heading level={3} color="var(--ggui-color-primary-900)">Task Board</Heading>
            </Stack>
            <Stack direction="horizontal" gap="var(--ggui-spacing-6)" align="center">
              <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                <Text variant="label" color="var(--ggui-color-primary-700)">Total: {totalTasks}</Text>
              </Stack>
              <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                <Text variant="label" color="var(--ggui-color-success-700)">Completed: {completedTasks}</Text>
              </Stack>
              <Progress value={totalTasks > 0 ? (completedTasks / totalTasks) * 100 : 0} max={100} size="sm" variant="success" />
            </Stack>
          </Row>
        </Box>

        {/* Kanban Columns */}
        <Row gap="var(--ggui-spacing-4)" align="start">
          {props.columns?.map(column => {
            const columnId = column.id || '';
            const columnTasks = tasksPerColumn[columnId] || [];
            const isAddFormOpen = expandedAddForm === columnId;

            return (
              <Card key={columnId} padding="var(--ggui-spacing-4)" shadow="md" style={{ flex: '1 1 320px', minHeight: '600px', display: 'flex', flexDirection: 'column' }}>
                {/* Column Header */}
                <Stack gap="var(--ggui-spacing-3)" style={{ marginBottom: 'var(--ggui-spacing-3)' }}>
                  <Row justify="between" align="center">
                    <Heading level={4} color="var(--ggui-color-onSurface)">{column.name}</Heading>
                    <Badge variant="default" size="sm">{columnTasks.length}</Badge>
                  </Row>
                  <Divider orientation="horizontal" margin="0" />
                </Stack>

                {/* Task List */}
                <Stack gap="var(--ggui-spacing-2)" style={{ flex: '1 1 auto', overflowY: 'auto', marginBottom: 'var(--ggui-spacing-3)' }} role="list">
                  {columnTasks.map(task => (
                    <Card key={task.id} padding="var(--ggui-spacing-3)" shadow="sm" border={true} as={Hoverable} hoverStyle={{ background: 'var(--ggui-color-surfaceVariant)' }} role="listitem">
                      <Stack gap="var(--ggui-spacing-2)">
                        {/* Task Title */}
                        {editingTaskId === task.id ? (
                          <Stack gap="var(--ggui-spacing-2)">
                            <Input
                              label="Edit task"
                              value={editingTitle}
                              onChange={setEditingTitle}
                              size="sm"
                              onKeyDown={(e: React.KeyboardEvent<HTMLInputElement>) => {
                                if (e.key === 'Enter') {
                                  handleEditTask(task.id!, editingTitle);
                                } else if (e.key === 'Escape') {
                                  setEditingTaskId(null);
                                  setEditingTitle('');
                                }
                              }}
                            />
                          </Stack>
                        ) : (
                          <Row gap="var(--ggui-spacing-2)" align="center" justify="between">
                            <Text as={Clickable} onDoubleClick={() => { setEditingTaskId(task.id); setEditingTitle(task.title || ''); }} variant="body" style={{ cursor: 'pointer', textDecoration: 'underline dashed' }} onKeyDown={(e: React.KeyboardEvent<HTMLElement>) => { if (e.key === 'Enter') { setEditingTaskId(task.id); setEditingTitle(task.title || ''); } }}>
                              {task.title}
                            </Text>
                            <Button size="xs" variant="ghost" onClick={() => { setEditingTaskId(task.id); setEditingTitle(task.title || ''); }} aria-label="Edit task">
                              <Icon name="edit-2" size={16} />
                            </Button>
                          </Row>
                        )}

                        {/* Priority Badge */}
                        {task.priority && (
                          <Badge variant={getPriorityVariant(task.priority)} size="sm" pill>
                            {task.priority}
                          </Badge>
                        )}

                        {/* Assignee & Due Date */}
                        {(task.assignee || task.dueDate) && (
                          <Row gap="var(--ggui-spacing-2)" align="center">
                            {task.assignee && (
                              <Avatar name={task.assignee} size="xs" />
                            )}
                            {task.dueDate && (
                              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{task.dueDate}</Text>
                            )}
                          </Row>
                        )}

                        {/* Action Buttons */}
                        <Row gap="var(--ggui-spacing-1)" justify="between">
                          {editingTaskId === task.id ? (
                            <>
                              <Button size="xs" variant="primary" onClick={() => handleEditTask(task.id!, editingTitle)} aria-label="Save task">Save</Button>
                              <Button size="xs" variant="ghost" onClick={() => { setEditingTaskId(null); setEditingTitle(''); }} aria-label="Cancel editing">Cancel</Button>
                            </>
                          ) : (
                            <Dropdown
                              trigger={<Button size="xs" variant="outline">Move</Button>}
                              options={props.columns?.filter(c => c.id !== columnId).map(c => ({ value: c.id || '', label: c.name || '' })) || []}
                              value=""
                              onChange={(newCol) => handleMoveTask(task.id!, newCol)}
                              placement="bottom-end"
                            />
                          )}
                        </Row>
                      </Stack>
                    </Card>
                  ))}. 
                </Stack>

                {/* Add Task Form — only in To Do column */}
                {columnId === toDoColumnId && (
                  <Stack gap="var(--ggui-spacing-2)" style={{ marginTop: 'auto' }}>
                    {isAddFormOpen ? (
                      <Card padding="var(--ggui-spacing-3)" shadow="sm" border={true}>
                        <Stack gap="var(--ggui-spacing-2)">
                          <Input
                            label="Task title"
                            placeholder="Enter task title..."
                            value={newTaskTitle}
                            onChange={setNewTaskTitle}
                            size="sm"
                            onKeyDown={(e: React.KeyboardEvent<HTMLInputElement>) => {
                              if (e.key === 'Enter') {
                                handleCreateTask();
                              } else if (e.key === 'Escape') {
                                setExpandedAddForm(null);
                                setNewTaskTitle('');
                              }
                            }}
                          />
                          <Select
                            label="Priority"
                            value={newTaskPriority}
                            onChange={(v) => setNewTaskPriority(v as 'low' | 'medium' | 'high')}
                            options={[
                              { value: 'low', label: 'Low' },
                              { value: 'medium', label: 'Medium' },
                              { value: 'high', label: 'High' },
                            ]}
                            size="sm"
                          />
                          <Row gap="var(--ggui-spacing-1)" justify="between">
                            <Button size="xs" variant="primary" onClick={() => handleCreateTask()}>Add Task</Button>
                            <Button size="xs" variant="ghost" onClick={() => { setExpandedAddForm(null); setNewTaskTitle(''); }}>Cancel</Button>
                          </Row>
                        </Stack>
                      </Card>
                    ) : (
                      <Button size="sm" variant="ghost" fullWidth onClick={() => setExpandedAddForm(columnId)} aria-label="Add new task to this column">+ Add Task</Button>
                    )}
                  </Stack>
                )}
              </Card>
            );
          })}
        </Row>
}

