  // Filter elements based on search query
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return props.elements;
    const query = searchQuery.toLowerCase();
    return props.elements.filter(el =>
      (el.name?.toLowerCase().includes(query) || el.symbol?.toLowerCase().includes(query))
    );
  }, [searchQuery, props.elements]);

  // Get unique categories with colors
  const categoriesMap = useMemo(() => {
    const categories = new Map<string, string>();
    const colorMap: Record<string, string> = {
      'alkali metal': 'var(--ggui-color-primary-100)',
      'alkaline earth metal': 'var(--ggui-color-primary-200)',
      'transition metal': 'var(--ggui-color-warning-100)',
      'lanthanide': 'var(--ggui-color-success-100)',
      'actinide': 'var(--ggui-color-error-100)',
      'nonmetal': 'var(--ggui-color-info-100)',
      'metalloid': 'var(--ggui-color-warning-200)',
      'halogen': 'var(--ggui-color-error-200)',
      'noble gas': 'var(--ggui-color-success-200)',
    };
    props.elements.forEach(el => {
      if (el.category && !categories.has(el.category)) {
        categories.set(el.category, colorMap[el.category.toLowerCase()] || 'var(--ggui-color-surfaceVariant)');
      }
    });
    return categories;
  }, [props.elements]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header */}
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={1}>Periodic Table of Elements</Heading>
          <SearchField
            value={searchQuery}
            onChange={setSearchQuery}
            placeholder="Search by name or symbol..."
            size="md"
          />
        </Stack>

        {/* Legend */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Stack direction="horizontal" gap="var(--ggui-spacing-3)" wrap align="center">
            {Array.from(categoriesMap.entries()).map(([category, color]) => (
              <Row key={category} gap="var(--ggui-spacing-1)" align="center">
                <Box
                  padding="var(--ggui-spacing-2)"
                  background={color}
                  borderRadius="var(--ggui-shape-radius-sm)"
                  style={{ minWidth: '16px', minHeight: '16px' }}
                />
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">{category}</Text>
              </Row>
            ))}
          </Stack>
        </Card>

        {/* Periodic Table Grid */}
        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-2)',
