            background: 'var(--ggui-color-surfaceVariant)',
            borderRadius: 'var(--ggui-shape-radius-lg)',
          }}
        >
          {filteredElements.map(element => {
            if (!element.row || !element.col) return null;
            const color = element.category
              ? categoriesMap.get(element.category) || 'var(--ggui-color-surface)'
              : 'var(--ggui-color-surface)';
            return (
              <Card
                key={`${element.atomicNumber}`}
                as={Clickable}
                onClick={() => setSelectedElement(element)}
                padding="var(--ggui-spacing-2)"
                shadow="sm"
                style={{
                  gridRow: element.row,
                  gridColumn: element.col,
                  background: color,
                  cursor: 'pointer',
                  minHeight: '80px',
                  display: 'flex',
                  flexDirection: 'column',
                  justifyContent: 'center',
                  alignItems: 'center',
                  position: 'relative',
                  transition: 'all 200ms ease-in-out',
                }}
                hoverStyle={{ opacity: 0.8 }}
              >
                <Text
                  variant="overline"
                  size="xs"
                  color="var(--ggui-color-onSurfaceVariant)"
                  style={{ position: 'absolute', top: 'var(--ggui-spacing-1)', left: 'var(--ggui-spacing-1)' }}
                >
                  {element.atomicNumber}
                </Text>
                <Text
                  variant="body"
                  size="2xl"
                  weight="bold"
                  color="var(--ggui-color-onSurface)"
                  align="center"
                >
                  {element.symbol}
                </Text>
              </Card>
            );
          })}
        </Box>

        {/* Detail Panel */}
        {selectedElement && (
          <Card padding="var(--ggui-spacing-4)" shadow="md">
            <Stack gap="var(--ggui-spacing-3)">
              <Row justify="between" align="center">
                <Heading level={2}>{selectedElement.name}</Heading>
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => setSelectedElement(null)}
                >
                  Close
                </Button>
              </Row>
              <Divider />
              <Stack gap="var(--ggui-spacing-2)">
                <Row justify="between">
                  <Text variant="label">Symbol:</Text>
                  <Text variant="body" color="var(--ggui-color-primary-600)">{selectedElement.symbol}</Text>
                </Row>
                <Row justify="between">
                  <Text variant="label">Atomic Number:</Text>
                  <Text variant="body">{selectedElement.atomicNumber}</Text>
                </Row>
                <Row justify="between">
                  <Text variant="label">Atomic Weight:</Text>
                  <Text variant="body">{selectedElement.atomicWeight?.toFixed(2)}</Text>
                </Row>
                <Row justify="between">
                  <Text variant="label">Category:</Text>
                  <Badge variant="primary">{selectedElement.category}</Badge>
                </Row>
              </Stack>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

