import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id?: string; name?: string; price?: number; currency?: string; rating?: number; reviewCount?: number; stock?: number; description?: string; specifications?: unknown[]; reviews?: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  // State management
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  // Derived values
  const isInStock = (props.product.stock ?? 0) > 0;
  const isLowStock = (props.product.stock ?? 0) > 0 && (props.product.stock ?? 0) <= 5;
  const stockBadgeVariant = isLowStock ? 'warning' : 'success';
  const stockBadgeText = isLowStock ? 'Low Stock' : 'In Stock';
   const maxQuantity = props.product.stock ?? 1;

  // Handlers
  const handleQuantityChange = useCallback((newQty: number) => {
    setQuantity(Math.max(1, Math.min(maxQuantity, newQty)));
  }, [maxQuantity]);

  const handleAddToCart = useCallback(() => {
    if (props.product.id) {
      addToCart({ productId: props.product.id, quantity });
    }
  }, [props.product.id, quantity, addToCart]);

  // Helper: render star rating
   const renderStars = (rating: number) => {
     const fullStars = Math.floor(rating);
     const hasHalfStar = rating % 1 !== 0;
     const emptyStars = 5 - Math.ceil(rating);
     return (
       <Row gap="var(--ggui-spacing-1)" align="center" role="img" aria-label={`${rating.toFixed(1)} out of 5 stars, ${props.product.reviewCount ?? 0} reviews`}>
         {Array.from({ length: fullStars }).map((_, i) => (
           <Icon key={`full-${i}`} name="star" size={16} color="var(--ggui-color-warning-500)" aria-hidden="true" />
         ))}
          {hasHalfStar && <Icon name="star" size={16} color="var(--ggui-color-warning-500)" aria-hidden="true" />}
         {Array.from({ length: emptyStars }).map((_, i) => (
           <Icon key={`empty-${i}`} name="star" size={16} color="var(--ggui-color-outlineVariant)" aria-hidden="true" />
         ))}
         <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" is="span">
           {rating.toFixed(1)} ({props.product.reviewCount ?? 0} reviews)
         </Text>
       </Row>
     );
   };

  // Helper: render specifications table
  const renderSpecifications = () => {
    const specs = props.product.specifications as any[] | undefined;
    if (!specs || specs.length === 0) {
      return <Text color="var(--ggui-color-onSurfaceVariant)">No specifications available</Text>;
    }

    return (
      <Table
        columns={[
          { key: 'key', header: 'Property', width: '40%' },
          { key: 'value', header: 'Value', width: '60%' },
        ]}
        data={specs}
        striped
        compact
      />
    );
  };

  // Helper: render reviews list
  const renderReviews = () => {
    const reviews = props.product.reviews as any[] | undefined;
    if (!reviews || reviews.length === 0) {
      return <Text color="var(--ggui-color-onSurfaceVariant)">No reviews yet</Text>;
    }

    return (
      <Stack gap="var(--ggui-spacing-4)">
        {reviews.map((review: any, idx: number) => (
          <Card key={idx} padding="var(--ggui-spacing-4)" shadow="sm">
            <Stack gap="var(--ggui-spacing-2)">
              <Row gap="var(--ggui-spacing-2)" align="center" justify="between">
                <Text variant="label" color="var(--ggui-color-onSurface)">{review.author ?? 'Anonymous'}</Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  {review.date ? new Date(review.date).toLocaleDateString() : 'N/A'}
                </Text>
              </Row>
              <Row gap="var(--ggui-spacing-1)" align="center">
                {Array.from({ length: 5 }).map((_, i) => (
                  <Icon
                    key={i}
                    name="star"
                    size={14}
                    color={i < (review.rating ?? 0) ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outlineVariant)'}
                  />
                ))}
              </Row>
              <Text variant="body" color="var(--ggui-color-onSurface)">{review.text ?? 'No comment'}</Text>
            </Stack>
          </Card>
        ))}
      </Stack>
    );
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* Top Section: Image + Details */}
        <Row gap="var(--ggui-spacing-8)" align="start" wrap>
          {/* Product Image */}
           <Box
             role="img"
             aria-label={`Product image placeholder for ${props.product.name}`}
             style={{
               width: '100%',
               maxWidth: '400px',
               aspectRatio: '1 / 1',
               background: 'var(--ggui-color-primary-50)',
               borderRadius: 'var(--ggui-shape-radius-lg)',
               display: 'flex',
               alignItems: 'center',
               justifyContent: 'center',
               flexShrink: 0,
             }}
           >
             <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
               <Icon name="image" size={48} color="var(--ggui-color-primary-300)" aria-hidden="true" />
               <Text variant="caption" color="var(--ggui-color-primary-600)">{props.product.name}</Text>
             </Stack>
           </Box>

          {/* Product Details */}
           <Stack gap="var(--ggui-spacing-4)" style={{ flex: 1, minWidth: '0', flexWrap: 'wrap' }}>
            {/* Title */}
            <Heading level={1} color="var(--ggui-color-onSurface)">{props.product.name}</Heading>

            {/* Price */}
            <Text
              variant="bodyLarge"
              size="2xl"
              weight="bold"
              color="var(--ggui-color-primary-600)"
            >
               {`${props.product.currency}${props.product.price?.toFixed(2) ?? '0.00'}`}
            </Text>

            {/* Rating */}
            {props.product.rating !== undefined && renderStars(props.product.rating)}

            {/* Stock Badge */}
            <Badge variant={stockBadgeVariant} size="md">
              {stockBadgeText}
            </Badge>
          </Stack>
        </Row>

        {/* Middle Section: Tabs */}
        <Tabs
          variant="line"
          size="md"
          activeKey={activeTab}
          onChange={setActiveTab}
          items={[
            {
              key: 'description',
              label: 'Description',
              content: (
                 <Stack gap="var(--ggui-spacing-3)">
                  <Text variant="body" color="var(--ggui-color-onSurface)">
                    {props.product.description || 'No description available'}
                  </Text>
                </Stack>
              ),
            },
            {
              key: 'specifications',
              label: 'Specifications',
              content: (
                 <Stack gap="var(--ggui-spacing-3)">
                  {renderSpecifications()}
                </Stack>
              ),
            },
            {
              key: 'reviews',
              label: 'Reviews',
              content: (
                 <Stack gap="var(--ggui-spacing-3)">
                  {renderReviews()}
                </Stack>
              ),
            },
          ]}
        />

        {/* Bottom Section: Quantity Selector + Add to Cart */}
         <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)" direction="horizontal" align="center" justify="between" wrap>
            {/* Quantity Selector */}
            <Stack gap="var(--ggui-spacing-2)" direction="horizontal" align="center">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Quantity:</Text>
               <Button
                 variant="outline"
                 size="sm"
                 aria-label="Decrease quantity"
                 onClick={() => handleQuantityChange(quantity - 1)}
                 disabled={quantity <= 1}
               >
                 −
               <Box
                 role="status"
                 aria-live="polite"
                 aria-label={`Current quantity: ${quantity}`}
                 style={{
                   minWidth: '48px',
                   textAlign: 'center',
                   padding: 'var(--ggui-spacing-2)',
                 }}
               >
                 <Text variant="body" color="var(--ggui-color-onSurface)" align="center">
                   {quantity}
                 </Text>
               </Box>
               <Button
                 variant="outline"
                 size="sm"
                 aria-label="Increase quantity"
                 onClick={() => handleQuantityChange(quantity + 1)}
                 disabled={quantity >= maxQuantity}
               >
                 +
            </Stack>

            {/* Add to Cart Button */}
            <Button
              variant="primary"
              size="lg"
              onClick={handleAddToCart}
              disabled={!isInStock}
              fullWidth={false}
            >
              Add to Cart
            </Button>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

