  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // State management
  const [inputText, setInputText] = useState('');
  const [allMessages, setAllMessages] = useState(props.messages || []);
  const [typingUsers, setTypingUsers] = useState<Set<string>>(new Set());
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom when new messages arrive
  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [allMessages, scrollToBottom]);

  // Handle new message from stream
  useEffect(() => {
    if (message.latest && message.latest.text) {
      setAllMessages((prev) => [...prev, message.latest!]);
    }
  }, [message.latest]);

  // Handle typing indicator from stream
  useEffect(() => {
    if (typing.latest && typing.latest.sender) {
      setTypingUsers((prev) => {
        const updated = new Set(prev);
        if (typing.latest!.active) {
          updated.add(typing.latest!.sender!);
        } else {
          updated.delete(typing.latest!.sender!);
        }
        return updated;
      });
    }
  }, [typing.latest]);

  // Handle send message
  const handleSendMessage = useCallback(() => {
    if (inputText.trim()) {
      const timestamp = new Date().toISOString();
      sendMessage({ text: inputText.trim(), timestamp });
      setInputText('');
    }
  }, [inputText, sendMessage]);

  // Handle Enter key (without Shift)
  const handleKeyDown = useCallback((e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  }, [handleSendMessage]);

  // Group consecutive messages from same sender
  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender?: string; messages: Array<{ text?: string; timestamp?: string }> }> = [];
    allMessages.forEach((msg) => {
      const lastGroup = groups[groups.length - 1];
      if (lastGroup && lastGroup.sender === msg.sender) {
        lastGroup.messages.push({ text: msg.text, timestamp: msg.timestamp });
      } else {
        groups.push({
          sender: msg.sender,
          messages: [{ text: msg.text, timestamp: msg.timestamp }],
        });
      }
    });
    return groups;
  }, [allMessages]);

  // Format timestamp for display
  const formatTime = (timestamp?: string): string => {
    if (!timestamp) return '';
    try {
      const date = new Date(timestamp);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch {
      return '';
    }
  };

  return (
    <Container maxWidth="4xl" padding="var(--ggui-spacing-6)">
      <Card shadow="md" radius="lg" padding="0" border={true}>
        <Stack gap="0" direction="vertical" align="stretch">
          {/* Header */}
          <Box paddingX="var(--ggui-spacing-6)" paddingY="var(--ggui-spacing-4)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-lg)" style={{ borderBottomLeftRadius: '0', borderBottomRightRadius: '0' }}>
            <Row justify="between" align="center">
              <Stack direction="horizontal" gap="var(--ggui-spacing-3)" align="center">
                <Heading level={3} color="var(--ggui-color-primary-900)">{props.title}</Heading>
                <Badge variant="primary" size="sm">{props.participantCount} participants</Badge>
              </Stack>
              {typingUsers.size > 0 && (
                <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                  <Spinner size={16} color="var(--ggui-color-primary-600)" aria-label="User typing indicator" />
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                    {Array.from(typingUsers).join(', ')} {typingUsers.size === 1 ? 'is' : 'are'} typing...
                  </Text>
                </Stack>
              )}
            </Row>
          </Box>

          {/* Message List */}
           <Box padding="var(--ggui-spacing-4)" style={{ flex: '1', minHeight: '400px', maxHeight: '500px', overflowY: 'auto', background: 'var(--ggui-color-surface)' }} role="region" aria-label="Chat messages">
             <Stack gap="var(--ggui-spacing-3)" direction="vertical" align="stretch">
               {groupedMessages.length === 0 ? (
                 <Box padding="var(--ggui-spacing-6)" style={{ textAlign: 'center' }}>
                   <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">No messages yet. Start the conversation!</Text>
                 </Box>
               ) : (
                 groupedMessages.map((group, groupIdx) => {
                   const isCurrentUser = group.sender === props.currentUser;
                   const bgColor = isCurrentUser ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)';
                   const textColor = isCurrentUser ? 'white' : 'var(--ggui-color-onSurface)';
                   const align = isCurrentUser ? 'end' : 'start';

                   return (
                     <Stack key={`group-${groupIdx}`} gap="var(--ggui-spacing-1)" direction="vertical" align={align}>
                       {group.messages.map((msg, msgIdx) => (
                         <Stack
                           key={`msg-${groupIdx}-${msgIdx}`}
                           gap="var(--ggui-spacing-2)"
                           direction="vertical"
                           align="start"
                           style={{
                             background: bgColor,
                             maxWidth: '70%',
                             marginLeft: isCurrentUser ? 'auto' : '0',
                             marginRight: isCurrentUser ? '0' : 'auto',
                             padding: 'var(--ggui-spacing-3)',
                             borderRadius: 'var(--ggui-shape-radius-md)',
                             boxShadow: 'var(--ggui-shape-shadow-sm)',
                           }}
                         >
                           <Text variant="label" color={textColor} weight="semibold">{group.sender}</Text>
                           <Text variant="body" color={textColor}>{msg.text}</Text>
                           <Text variant="caption" color={isCurrentUser ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-onSurfaceVariant)'}>
                             {formatTime(msg.timestamp)}
                           </Text>
                         </Stack>
                       ))}
                     </Stack>
                   );
                 })
                )}
            </Stack>
          </Box>

          {/* Input Area */}
           <Box paddingX="var(--ggui-spacing-4)" paddingY="var(--ggui-spacing-4)" background="var(--ggui-color-surface)" style={{ borderTopLeftRadius: '0', borderTopRightRadius: '0', borderTop: '1px solid var(--ggui-color-outlineVariant)' }}>
            <Row gap="var(--ggui-spacing-3)" align="end" justify="start">
              <TextArea
                label="Message"
                value={inputText}
                onChange={setInputText}
                onKeyDown={handleKeyDown}
                placeholder="Type a message (Enter to send, Shift+Enter for newline)..."
                rows={3}
                style={{ flex: '1' }}
              />
              <Button
                variant="primary"
                size="md"
                onClick={handleSendMessage}
                disabled={!inputText.trim()}
              >
                Send
              </Button>
            </Row>
          </Box>
        </Stack>
      </Card>
    </Container>
  );
}

