interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State for merged stock data and last update timestamp
  const [stocks, setStocks] = useState(props.stocks || []);
  const [lastUpdated, setLastUpdated] = useState<string>('');
  const [animatingSymbols, setAnimatingSymbols] = useState<Set<string>>(new Set());

  // Update last updated timestamp when price updates arrive
  useEffect(() => {
    if (priceUpdate.latest) {
      const now = new Date();
      setLastUpdated(now.toLocaleTimeString());

      // Mark this symbol as animating
      if (priceUpdate.latest.symbol) {
        setAnimatingSymbols(prev => new Set([...prev, priceUpdate.latest.symbol!]));
        setTimeout(() => {
          setAnimatingSymbols(prev => {
            const next = new Set(prev);
            next.delete(priceUpdate.latest.symbol!);
            return next;
          });
        }, 600); // Match animation duration
      }

      // Merge updated stock data
      setStocks(prevStocks =>
        prevStocks.map(stock =>
          stock.symbol === priceUpdate.latest?.symbol
            ? {
                ...stock,
                price: priceUpdate.latest.price ?? stock.price,
                change: priceUpdate.latest.change ?? stock.change,
                changePercent: priceUpdate.latest.changePercent ?? stock.changePercent,
              }
            : stock
        )
      );
    }
  }, [priceUpdate.latest]);

  // Format price with 2 decimals
  const formatPrice = useCallback((price: number | undefined) => {
    if (price === undefined) return '$0.00';
    return `$${price.toFixed(2)}`;
  }, []);

  // Format percentage with sign and 2 decimals
  const formatPercent = useCallback((percent: number | undefined) => {
    if (percent === undefined) return '0.00%';
    const sign = percent > 0 ? '+' : '';
    return `${sign}${percent.toFixed(2)}%`;
  }, []);

  // Determine color based on change
  const getChangeColor = useCallback((change: number | undefined) => {
    if (change === undefined) return 'var(--ggui-color-onSurface)';
    return change >= 0 ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)';
  }, []);

  // Determine border color based on change
  const getChangeBorderColor = useCallback((change: number | undefined) => {
    if (change === undefined) return 'var(--ggui-color-outlineVariant)';
    return change >= 0 ? 'var(--ggui-color-success-200)' : 'var(--ggui-color-error-200)';
  }, []);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header with title and last updated timestamp */}
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={1} color="var(--ggui-color-onSurface)">
            Market Watch
          </Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
            {lastUpdated ? `Last Updated: ${lastUpdated}` : 'Waiting for updates...'}
          </Text>
        </Stack>

        {/* Responsive grid of stock cards */}
        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
            gap: 'var(--ggui-spacing-4)',
          }}
        >
          {stocks.map((stock) => {
            const isAnimating = animatingSymbols.has(stock.symbol || '');
            const changeColor = getChangeColor(stock.change);
            const changeBorderColor = getChangeBorderColor(stock.change);
            const isPositive = (stock.change ?? 0) >= 0;

            return (
              <Card
                key={stock.symbol}
                padding="var(--ggui-spacing-4)"
                shadow="md"
                radius="lg"
                border={true}
                style={{
                  borderColor: changeBorderColor,
                  animation: isAnimating
                    ? 'flash 600ms ease-out'
                    : 'none',
                  '--ggui-flash-color': isPositive
                    ? 'var(--ggui-color-success-100)'
                    : 'var(--ggui-color-error-100)',
                } as React.CSSProperties}
              >
                <Stack gap="var(--ggui-spacing-3)">
                  {/* Ticker symbol - large and bold */}
                  <Text
                    variant="body"
                    size="2xl"
                    weight="bold"
                    color="var(--ggui-color-onSurface)"
                  >
                    {stock.symbol || 'N/A'}
                  </Text>

                  {/* Company name */}
                  <Text
                    variant="bodySmall"
                    color="var(--ggui-color-onSurfaceVariant)"
                  >
                    {stock.name || 'Unknown'}
                  </Text>

                  {/* Current price */}
                  <Text
                    variant="body"
                    size="lg"
                    weight="semibold"
                    color="var(--ggui-color-onSurface)"
                  >
                    {formatPrice(stock.price)}
                  </Text>

                  {/* Change amount and percentage with arrow */}
                  <Row
                    gap="var(--ggui-spacing-2)"
                    align="center"
                  >
                    <Text
                      variant="body"
                      color={changeColor}
                      weight="semibold"
                    >
                      {stock.change !== undefined && stock.change !== 0
                        ? (stock.change > 0 ? '+' : '') + stock.change.toFixed(2)
                        : '0.00'}
                    </Text>
                    <Text
                      variant="body"
                      color={changeColor}
                      weight="semibold"
                    >
                      {isPositive ? '▲' : '▼'} {formatPercent(stock.changePercent)}
                    </Text>
                  </Row>
                </Stack>
              </Card>
            );
          })}
        </Box>
      </Stack>
    </Container>
  );
}
