type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





export default function Component(props: Props) {
  // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete');

  // State management
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile.name || '',
    email: props.initialProfile.email || '',
    avatar: props.initialProfile.avatar || (props.avatarOptions[0] || ''),
    role: props.initialProfile.role || '',
    emailNotifications: props.initialProfile.emailNotifications ?? true,
    theme: props.initialProfile.theme || 'light',
  });

  // Validation state
  const [errors, setErrors] = useState<Record<string, string>>({});

  // Helper: validate email format
  const isValidEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  // Helper: validate required fields for current step
  const validateStep = (step: number): boolean => {
    const newErrors: Record<string, string> = {};

    if (step === 1) {
      if (!formData.name.trim()) newErrors.name = 'Name is required';
      if (!formData.email.trim()) newErrors.email = 'Email is required';
      else if (!isValidEmail(formData.email)) newErrors.email = 'Invalid email format';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  // Handler: Next button
  const handleNext = useCallback(() => {
    if (validateStep(currentStep)) {
      setCurrentStep(prev => Math.min(prev + 1, 3));
    }
  }, [currentStep, formData]);

  // Handler: Back button
  const handleBack = useCallback(() => {
    setCurrentStep(prev => Math.max(prev - 1, 1));
  }, []);

  // Handler: Complete setup
  const handleComplete = useCallback(() => {
    if (validateStep(3)) {
      complete({
        name: formData.name,
        email: formData.email,
        avatar: formData.avatar,
        role: formData.role,
        emailNotifications: formData.emailNotifications,
        theme: formData.theme,
      });
    }
  }, [formData, complete]);

  // Handler: Update form data
  const updateFormData = useCallback((field: string, value: unknown) => {
    setFormData(prev => ({
      ...prev,
      [field]: value,
    }));
    // Clear error for this field when user starts editing
    if (errors[field]) {
      setErrors(prev => ({
        ...prev,
        [field]: '',
      }));
    }
  }, [errors]);

  // Compute progress percentage
  const progress = (currentStep / 3) * 100;

  // Determine if Next button should be disabled
  const isNextDisabled = currentStep === 1 && (Object.keys(errors).length > 0 || !formData.name.trim() || !formData.email.trim());

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header */}
        <Stack gap="var(--ggui-spacing-3)" align="center">
          <Heading level={1} align="center">Profile Setup</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)" align="center">
            Step {currentStep} of 3
          </Text>
        </Stack>

        {/* Progress Bar */}
        <Progress value={progress} max={100} size="md" variant="default" />

        {/* Step 1: Profile Setup */}
        {currentStep === 1 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2} color="var(--ggui-color-onSurface)">Your Profile</Heading>

              {/* Name Input */}
              <Input
                label="Full Name"
                placeholder="John Doe"
                value={formData.name}
                onChange={(value) => updateFormData('name', value)}
                error={errors.name}
                required
              />

              {/* Email Input */}
              <Input
                label="Email Address"
                type="email"
                placeholder="you@example.com"
                value={formData.email}
                onChange={(value) => updateFormData('email', value)}
                error={errors.email}
                required
              />

              {/* Avatar Selection */}
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                  Choose Your Avatar
                </Text>
                <Row gap="var(--ggui-spacing-3)" align="center" wrap>
                  {props.avatarOptions.map((avatar) => (
                    <Box
                      key={avatar}
                      as={Clickable}
                      onClick={() => updateFormData('avatar', avatar)}
                      padding="var(--ggui-spacing-2)"
                      borderRadius="var(--ggui-shape-radius-md)"
                      background={formData.avatar === avatar ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-surfaceVariant)'}
                      style={{ cursor: 'pointer', transition: 'all 200ms ease' }}
                    >
                      <Text size="3xl">{avatar}</Text>
                    </Box>
                  ))}
                </Row>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 2: Preferences */}
        {currentStep === 2 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2} color="var(--ggui-color-onSurface)">Your Preferences</Heading>

              {/* Role Selection */}
              <Select
                label="Role"
                value={formData.role}
                onChange={(value) => updateFormData('role', value)}
                options={props.roleOptions.map((role) => ({
                  value: role.toLowerCase().replace(/\s+/g, '-'),
                  label: role,
                }))}
                placeholder="Select a role"
              />

              {/* Email Notifications Toggle */}
              <Toggle
                label="Email Notifications"
                checked={formData.emailNotifications}
                onChange={(checked) => updateFormData('emailNotifications', checked)}
                size="md"
              />

              {/* Theme Preference */}
              <RadioGroup
                label="Theme Preference"
                value={formData.theme}
                onChange={(value) => updateFormData('theme', value)}
                options={[
                  { value: 'light', label: 'Light' },
                  { value: 'dark', label: 'Dark' },
                ]}
                direction="horizontal"
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Review & Confirm */}
        {currentStep === 3 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2} color="var(--ggui-color-onSurface)">Review Your Setup</Heading>

              {/* Summary Card */}
              <Card padding="var(--ggui-spacing-4)" border={true} background="var(--ggui-color-surfaceVariant)">
                <Stack gap="var(--ggui-spacing-3)">
                  {/* Profile Section */}
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">PROFILE</Text>
                    <Row gap="var(--ggui-spacing-3)" align="center">
                      <Text size="2xl">{formData.avatar}</Text>
                      <Stack gap="var(--ggui-spacing-1)">
                        <Text variant="body" color="var(--ggui-color-onSurface)">{formData.name}</Text>
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">{formData.email}</Text>
                      </Stack>
                    </Row>
                  </Stack>

                  <Divider margin="var(--ggui-spacing-2)" />

                  {/* Preferences Section */}
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">PREFERENCES</Text>
                    <Row gap="var(--ggui-spacing-3)" align="center" wrap>
