  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object
  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [touched, setTouched] = useState<{ name: boolean; email: boolean }>({ name: false, email: false });

  const emailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const nameError = touched.name && name.trim().length === 0 ? 'Name is required' : '';
  const emailError = touched.email && email.trim().length === 0 ? 'Email is required' : touched.email && !emailValid ? 'Please enter a valid email address' : '';

  const canProceed = useMemo(() => {
    if (step === 1) {
      return name.trim().length > 0 && emailValid;
    }
    if (step === 2) {
      return satisfaction !== '';
    }
    return true;
  }, [step, name, emailValid, satisfaction]);

  const satisfactionOptions = useMemo(() => {
    if (!Array.isArray(props.satisfactionLabels)) {
      return [];
    }
    return props.satisfactionLabels.slice(0, 5).map((label, index) => ({
      value: String(index + 1),
      label: `${index + 1} - ${label}`
    }));
  }, [props.satisfactionLabels]);

  const toggleFeature = useCallback((feature: string, checked: boolean) => {
    setFeatures((prev) => {
      if (checked) {
        if (prev.includes(feature)) {
          return prev;
        }
        return [...prev, feature];
      }
      return prev.filter((item) => item !== feature);
    });
  }, []);

  const handleNext = useCallback(() => {
    if (step === 1) {
      setTouched({ name: true, email: true });
      if (!(name.trim().length > 0 && emailValid)) {
        return;
      }
    }
    if (step === 2 && satisfaction === '') {
      return;
    }
    setStep((prev) => (prev < 5 ? prev + 1 : prev));
  }, [step, name, emailValid, satisfaction]);

  const handleBack = useCallback(() => {
    setStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const [submitError, setSubmitError] = useState('');

  const handleSubmit = useCallback(() => {
    if (satisfaction === '') {
      return;
    }
    try {
      const payload = {
        name: name.trim(),
        email: email.trim(),
        satisfaction: Number(satisfaction),
        features,
        comments: comments.trim()
      };
      submit(payload);
      setSubmitError('');
      if ((props as unknown as { onSubmit?: (data: ActionSubmitPayload) => void }).onSubmit) {
        (props as unknown as { onSubmit: (data: ActionSubmitPayload) => void }).onSubmit(payload);
      }
    } catch (error) {
      setSubmitError('Unable to submit survey. Please try again.');
    }
  }, [submit, name, email, satisfaction, features, comments, props]);
  const progressValue = (step / 5) * 100;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="md" border radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Heading level={3}>Survey Form</Heading>
              <Badge variant="primary">Step {step} of 5</Badge>
            </Row>
            <Progress value={progressValue} max={100} variant="default" size="md" aria-label="Survey progress" />
            <Divider margin="var(--ggui-spacing-2)" />

            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Your Information</Heading>
                <Input
                  label="Name"
                  placeholder="Enter your name"
                  value={name}
                  onChange={setName}
                  required
                  error={nameError}
                  onBlur={() => setTouched((prev) => ({ ...prev, name: true }))}
                />
                <Input
                  label="Email"
                  type="email"
                  placeholder="you@example.com"
                  value={email}
                  onChange={setEmail}
                  required
                  error={emailError}
                  onBlur={() => setTouched((prev) => ({ ...prev, email: true }))}
                />
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Satisfaction Rating</Heading>
                <RadioGroup
                  label="How satisfied are you?"
                  value={satisfaction}
                  onChange={setSatisfaction}
                  options={satisfactionOptions}
                  direction="vertical"
                  error={satisfaction === '' ? 'Please select a rating before continuing' : ''}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Feature Interests</Heading>
                <Text color="var(--ggui-color-onSurfaceVariant)">Select all that apply.</Text>
                <Stack gap="var(--ggui-spacing-3)">
                  {(Array.isArray(props.featureOptions) ? props.featureOptions : []).length === 0 ? (
                    <Text color="var(--ggui-color-onSurfaceVariant)">No feature options available</Text>
                  ) : (
                    (Array.isArray(props.featureOptions) ? props.featureOptions : []).map((feature) => (
                      <Checkbox
                        key={feature}
                        label={feature}
                        checked={features.includes(feature)}
                        onChange={(checked) => toggleFeature(feature, checked)}
                      />
                    ))
                  )}
                </Stack>
              </Stack>
            )}

            {step === 4 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Additional Comments</Heading>
                <TextArea
                  label="Comments (optional)"
                  placeholder="Share any additional feedback"
                  value={comments}
                  onChange={setComments}
                  maxLength={500}
                  showCount
                  rows={6}
                  helperText="Maximum 500 characters"
                />
              </Stack>
            )}

            {step === 5 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Review Your Answers</Heading>
                <Card padding="var(--ggui-spacing-4)" border radius="md" shadow="sm">
                  <Stack as="dl" gap="var(--ggui-spacing-3)">
                    <Row as="div" justify="between">
                      <Text is="label" variant="label" as="dt">Name</Text>
                      <Text is="span" as="dd">{name || '—'}</Text>
                    </Row>
                    <Row as="div" justify="between">
                      <Text is="label" variant="label" as="dt">Email</Text>
                      <Text is="span" as="dd">{email || '—'}</Text>
                    </Row>
                    <Row as="div" justify="between">
                      <Text is="label" variant="label" as="dt">Satisfaction</Text>
                      <Text is="span" as="dd">{satisfaction ? `${satisfaction} - ${props.satisfactionLabels[Number(satisfaction) - 1] || ''}` : '—'}</Text>
                    </Row>
                    <Stack as="div" gap="var(--ggui-spacing-1)">
                      <Text is="label" variant="label" as="dt">Features</Text>
                      <Text is="span" color="var(--ggui-color-onSurfaceVariant)" as="dd">{features.length > 0 ? features.join(', ') : 'No features selected'}</Text>
                    </Stack>
                    <Stack as="div" gap="var(--ggui-spacing-1)">
                      <Text is="label" variant="label" as="dt">Comments</Text>
                      <Text is="span" color="var(--ggui-color-onSurfaceVariant)" as="dd">{comments.trim().length > 0 ? comments : 'No comments provided'}</Text>
                    </Stack>
                  </Stack>
                </Card>
              </Stack>
            )}

            <Divider margin="var(--ggui-spacing-2)" />
            {submitError && <Alert variant="error">{submitError}</Alert>}
            <Row justify="between" align="center">
              <Button variant="outline" disabled={step === 1} onClick={handleBack}>
                Back
              </Button>
              {step < 5 ? (
                <Button variant="primary" disabled={!canProceed} onClick={handleNext}>
                  Next
                </Button>
              ) : (
                <Button variant="primary" onClick={handleSubmit}>
                  Submit Survey
                </Button>
              )}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

