      { id: 'done', name: 'Done' },
    ];
  }, [props.columns]);

  const tasksByColumn = useMemo(() => {
    return columnsToRender.reduce((acc, column) => {
      const key = column.id || 'unknown';
      acc[key] = localTasks.filter((task) => task.column === key);
      return acc;
    }, {} as Record<string, Array<{ id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate?: string }>>);
  }, [columnsToRender, localTasks]);

  const completedCount = useMemo(() => {
    const doneColumn = columnsToRender.find((col) => (col.name || '').toLowerCase() === 'done');
    if (!doneColumn?.id) return 0;
    return localTasks.filter((task) => task.column === doneColumn.id).length;
  }, [columnsToRender, localTasks]);

  const totalCount = localTasks.length;

  const getPriorityVariant = useCallback((priority: 'low' | 'medium' | 'high') => {
    if (priority === 'high') return 'error';
    if (priority === 'medium') return 'warning';
    return 'success';
  }, []);

  const handleMoveTask = useCallback(
    (taskId: string, nextColumn: string) => {
      const previous = localTasks;
      setLocalTasks((prev) => prev.map((task) => (task.id === taskId ? { ...task, column: nextColumn } : task)));
      try {
        taskUpdate({ action: 'move', taskId, data: { column: nextColumn } });
        setUpdateError('');
      } catch (_error) {
        setLocalTasks(previous);
        setUpdateError('Could not move task. Please retry.');
      }
    },
    [localTasks, taskUpdate],
  );

  const handleStartEdit = useCallback((taskId: string, currentTitle: string) => {
    setEditingTaskId(taskId);
    setEditingTitle(currentTitle);
  }, []);

  const handleSaveEdit = useCallback(
    (taskId: string) => {
      const safeTitle = editingTitle.trim() || 'Untitled task';
      const previous = localTasks;
      const editedTask = previous.find((task) => task.id === taskId);
      setLocalTasks((prev) => prev.map((task) => (task.id === taskId ? { ...task, title: safeTitle } : task)));
      try {
        taskUpdate({
          action: 'edit',
          taskId,
          data: {
            column: editedTask?.column || 'todo',
            title: safeTitle,
            priority: editedTask?.priority || 'low',
            assignee: editedTask?.assignee || 'NA',
            dueDate: editedTask?.dueDate || '',
          } as unknown as { column: string },
        });
        setUpdateError('');
      } catch (_error) {
        setLocalTasks(previous);
        setUpdateError('Could not save task edit. Please retry.');
      }
      setEditingTaskId('');
      setEditingTitle('');
    },
    [editingTitle, localTasks, taskUpdate],
  );

  const handleCreateTask = useCallback(
    (columnId: string) => {
      const newTitle = (newTitleByColumn[columnId] || '').trim();
      const newPriority = newPriorityByColumn[columnId] || 'low';
      if (!newTitle) {
        return;
      }
      const newTaskId = `task-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
      const task = {
        id: newTaskId,
        title: newTitle,
        priority: newPriority,
        assignee: 'NA',
        column: 'todo',
      } as { id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate?: string };
      const previous = localTasks;
      setLocalTasks((prev) => [...prev, task]);
      try {
        taskUpdate({
          action: 'create',
          taskId: newTaskId,
          data: {
            column: 'todo',
            title: newTitle,
            priority: newPriority,
            assignee: 'NA',
            dueDate: '',
          } as unknown as { column: string },
        });
        setUpdateError('');
      } catch (_error) {
        setLocalTasks(previous);
        setUpdateError('Could not create task. Please retry.');
      }
      setShowAddByColumn((prev) => ({ ...prev, [columnId]: false }));
      setNewTitleByColumn((prev) => ({ ...prev, [columnId]: '' }));
      setNewPriorityByColumn((prev) => ({ ...prev, [columnId]: 'low' }));
    },
    [localTasks, newPriorityByColumn, newTitleByColumn, taskUpdate],
  );

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-4)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Row justify="between" align="center">
            <Heading level={3}>Kanban Board</Heading>
            <Row gap="var(--ggui-spacing-3)">
              <Badge variant="primary">Total: {totalCount}</Badge>
              <Badge variant="success">Completed: {completedCount}</Badge>
            </Row>
          </Row>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
            Live updates received: {taskChanged.all.length}
          </Text>
          {updateError && <Alert variant="error">{updateError}</Alert>}
          {streamError && <Alert variant="warning">{streamError}</Alert>}
        </Card>
        <Row gap="var(--ggui-spacing-4)" align="start" wrap>
          {columnsToRender.map((column) => {
            const columnId = column.id || 'unknown';
            const items = tasksByColumn[columnId] || [];
            return (
              <Card
                key={columnId}
                padding="var(--ggui-spacing-4)"
                shadow="sm"
                radius="lg"
              >
                <Stack gap="var(--ggui-spacing-3)">
                  <Row justify="between" align="center">
                    <Heading level={5}>{column.name || 'Unnamed'}</Heading>
                    <Badge variant="default">{items.length}</Badge>
                  </Row>
                  <Divider margin="var(--ggui-spacing-1)" />

                  <Stack gap="var(--ggui-spacing-3)">
                    {items.length === 0 && (
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                        No tasks yet
                      </Text>
                    )}

                    {items.map((task) => (
                      <Card
                        key={task.id}
                        padding="var(--ggui-spacing-3)"
                        shadow="none"
                        border
                        radius="md"
                        as={Clickable}
                        onDoubleClick={() => handleStartEdit(task.id, task.title)}
                      >
                        <Stack gap="var(--ggui-spacing-2)">
                          {editingTaskId === task.id ? (
                            <Stack gap="var(--ggui-spacing-2)">
                              <Input
                                label="Edit task title"
                                value={editingTitle}
                                onChange={setEditingTitle}
                                placeholder="Task title"
                              />
                              <Row gap="var(--ggui-spacing-2)" align="center">
                                <Button variant="primary" onPress={() => handleSaveEdit(task.id)}>Save</Button>
                                <Button
                                  variant="ghost"
                                  onPress={() => {
                                    setEditingTaskId('');
                                    setEditingTitle(task.title);
                                  }}
                                >
                                  Cancel
                                </Button>
                              </Row>
                            </Stack>
                          ) : (
                            <Row justify="between" align="center">
                              <Button
                                variant="ghost"
                                size="sm"
                                onPress={() => handleStartEdit(task.id, task.title)}
                              >
                                {task.title}
                              </Button>
                              <Button variant="ghost" size="sm" onPress={() => handleStartEdit(task.id, task.title)}>
                                Edit
                              </Button>
                            </Row>
                          )}

                          <Row gap="var(--ggui-spacing-2)" align="center" wrap>
                            <Badge variant={getPriorityVariant(task.priority)}>{task.priority}</Badge>
                            <Avatar name={task.assignee || 'NA'} size="sm" />
                            {task.dueDate && <Tag variant="info">Due: {task.dueDate}</Tag>}
                          </Row>

                          <Select
                            label="Move task"
                            value={task.column}
                            onChange={(value) => handleMoveTask(task.id, value)}
                            options={columnsToRender
                              .filter((col) => (col.id || '') !== task.column)
                              .map((col) => ({ value: col.id || '', label: col.name || 'Unknown' }))}
                            placeholder="Move to..."
                          />
                        </Stack>
                      </Card>
                    ))}

                    {showAddByColumn[columnId] ? (
                      <Card padding="var(--ggui-spacing-3)" border radius="md" shadow="none">
                        <Stack gap="var(--ggui-spacing-2)">
                          <Input
                            label="Task title"
                            value={newTitleByColumn[columnId] || ''}
                            onChange={(value) => setNewTitleByColumn((prev) => ({ ...prev, [columnId]: value }))}
                            placeholder="Enter task title"
                          />
                          <Select
                            label="Priority"
                            value={newPriorityByColumn[columnId] || 'low'}
                            onChange={(value) =>
                              setNewPriorityByColumn((prev) => ({ ...prev, [columnId]: (value as 'low' | 'medium' | 'high') || 'low' }))
                            }
                            options={[
                              { value: 'low', label: 'Low' },
                              { value: 'medium', label: 'Medium' },
                              { value: 'high', label: 'High' },
                            ]}
                          />
                          <Row gap="var(--ggui-spacing-2)">
                            <Button variant="primary" onPress={() => handleCreateTask(columnId)}>Create</Button>
                            <Button
                              variant="ghost"
                              onPress={() => {
                                setShowAddByColumn((prev) => ({ ...prev, [columnId]: false }));
                                setNewTitleByColumn((prev) => ({ ...prev, [columnId]: '' }));
                              }}
                            >
                              Cancel
                            </Button>
                          </Row>
                        </Stack>
                      </Card>
                    ) : (
                      <Button
                        variant="outline"
                        onPress={() => {
                          setShowAddByColumn((prev) => ({ ...prev, [columnId]: true }));
                          setNewPriorityByColumn((prev) => ({ ...prev, [columnId]: prev[columnId] || 'low' }));
                        }}
                      >
                        Add Task
                      </Button>
                    )}
                  </Stack>
                </Card>
            );
          })}
        </Row>
      </Stack>
    </Container>

  );
}

