}




const getCategoryColor = (category?: string): string => {
  const key = (category || 'unknown').toLowerCase();
  if (key.includes('noble')) return 'var(--ggui-color-primary-300)';
  if (key.includes('halogen')) return 'var(--ggui-color-warning)';
  if (key.includes('alkali metal')) return 'var(--ggui-color-error)';
  if (key.includes('alkaline earth')) return 'var(--ggui-color-warning-500)';
  if (key.includes('transition')) return 'var(--ggui-color-info)';
  if (key.includes('post-transition')) return 'var(--ggui-color-primary-400)';
  if (key.includes('metalloid')) return 'var(--ggui-color-success)';
  if (key.includes('nonmetal')) return 'var(--ggui-color-success-500)';
  if (key.includes('lanthanide')) return 'var(--ggui-color-primary-500)';
  if (key.includes('actinide')) return 'var(--ggui-color-error-500)';
  return 'var(--ggui-color-outline)';
};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  const [searchQuery, setSearchQuery] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const normalizedElements = useMemo(() => {
    return (props.elements || []).map((element, index) => ({
      ...element,
      atomicNumber: element.atomicNumber ?? index + 1,
      symbol: element.symbol ?? '',
      name: element.name ?? 'Unknown',
      atomicWeight: element.atomicWeight ?? 0,
      category: element.category ?? 'unknown',
      row: element.row ?? 1,
      col: element.col ?? 1,
    }));
  }, [props.elements]);

  const filteredElements = useMemo(() => {
    const q = searchQuery.trim().toLowerCase();
    if (!q) return normalizedElements;
    return normalizedElements.filter((element) => {
      return element.name.toLowerCase().includes(q) || element.symbol.toLowerCase().includes(q);
    });
  }, [normalizedElements, searchQuery]);

  const categories = useMemo(() => {
    const unique = new Set<string>();
    normalizedElements.forEach((element) => unique.add(element.category));
    return Array.from(unique);
  }, [normalizedElements]);

  const selectedElement = useMemo(() => {
    if (selectedAtomicNumber === null) return null;
    return normalizedElements.find((e) => e.atomicNumber === selectedAtomicNumber) || null;
  }, [normalizedElements, selectedAtomicNumber]);

  useEffect(() => {
    if (selectedAtomicNumber === null) return;
    const exists = filteredElements.some((e) => e.atomicNumber === selectedAtomicNumber);
    if (!exists) {
      setSelectedAtomicNumber(null);
    }
  }, [filteredElements, selectedAtomicNumber]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={2}>Interactive Periodic Table</Heading>
