        </Stack>

        <Input
          label="Search elements"
          placeholder="Type element name or symbol"
          value={searchQuery}
          onChange={setSearchQuery}
        />

        {normalizedElements.length === 0 ? (
          <Alert variant="info" title="No element data">
            No elements were provided in props.elements.
          </Alert>
        ) : (
          <Card padding="var(--ggui-spacing-4)" border shadow="sm">
            <Box
              style={{
                overflowX: 'auto',
              }}
            >
              <Box
                style={{
                  display: 'grid',
                  gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
                  gap: 'var(--ggui-spacing-2)',
                  minWidth: '1080px',
                }}
              >
                {filteredElements.length === 0 ? (
                  <Box
                    style={{ gridColumn: '1 / span 18' }}
                    padding="var(--ggui-spacing-4)"
                    background="var(--ggui-color-surfaceVariant)"
                    borderRadius="var(--ggui-shape-radius-md)"
                  >
                    <Text color="var(--ggui-color-onSurfaceVariant)">No matching elements found.</Text>
                  </Box>
                ) : (
                  filteredElements.map((element) => (
                    <Card
                      key={element.atomicNumber}
                      as={Clickable}
                      onClick={() => setSelectedAtomicNumber(element.atomicNumber)}
                      aria-label={`${element.name}, atomic number ${element.atomicNumber}`}
                      padding="var(--ggui-spacing-2)"
                      shadow="none"
                      border
                      radius="md"
                      hoverStyle={{ opacity: 0.92 }}
                      pressStyle={{ transform: 'scale(0.98)' }}
                      style={{
                        position: 'relative',
                        gridColumn: `${element.col}`,
                        gridRow: `${element.row}`,
                        minHeight: 'var(--ggui-spacing-12)',
                        background: getCategoryColor(element.category),
                        borderColor: selectedAtomicNumber === element.atomicNumber ? 'var(--ggui-color-primary-700)' : 'var(--ggui-color-outline)',
                        outline: selectedAtomicNumber === element.atomicNumber ? '2px solid var(--ggui-color-primary-600)' : undefined,
                        outlineOffset: '2px',
                      }}
                    >
                      <Text
