                    <Box
                      padding="var(--ggui-spacing-1)"
                      style={{ maxHeight: '50vh', overflowY: 'auto' } as React.CSSProperties}
                    >
                      <Stack gap="var(--ggui-spacing-3)">
                        {(groupedMessages || []).map((group, groupIndex) => {
                          const isCurrentUser = group.sender === props.currentUser;
                          return (
                            <Stack
                              key={`${group.sender || 'unknown'}-${groupIndex}`}
align={isCurrentUser ? 'end' : 'start'}
                              gap="var(--ggui-spacing-1)"
                            >
                              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                {group.sender || 'Unknown'}
                              </Text>
                              <Stack gap="var(--ggui-spacing-1)" align={isCurrentUser ? 'end' : 'start'}>
                                {group.items.map((item, itemIndex) => (
                                  <Box
                                    key={`${groupIndex}-${itemIndex}-${item.timestamp || ''}`}
padding="var(--ggui-spacing-2)"
                                    borderRadius="var(--ggui-shape-radius-md)"
                                    background={
                                      isCurrentUser
                                        ? 'var(--ggui-color-primary-600)'
                                        : 'var(--ggui-color-surfaceVariant)'
                                    }
                                  >
                                    <Stack gap="var(--ggui-spacing-1)">
                                      <Text
                                        variant="bodySmall"
                                        color={
                                          isCurrentUser
                                            ? 'var(--ggui-color-onContainer)'
                                            : 'var(--ggui-color-onSurface)'
                                        }
                                      >
                                        {item.text || ''}
                                      </Text>
                                      <Text
                                        variant="caption"
                                        color={
                                          isCurrentUser
                                            ? 'var(--ggui-color-primary-100)'
                                            : 'var(--ggui-color-onSurfaceVariant)'
                                        }
                                      >
                                        {formatTimestamp(item.timestamp)}
                                      </Text>
                                    </Stack>
                                  </Box>
                                ))}
                              </Stack>
                            </Stack>
                          );
                        })}
                        {typingVisible ? (
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                            {typingState?.sender} is typing…
                          </Text>
                        ) : null}
                        <Box><div ref={endRef} /></Box>
