      setNowMs(Date.now());
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    if (!priceUpdate.latest || !priceUpdate.latest.symbol) {
      return;
    }
    setStocksState((prev) => {
      const safePrev = prev || [];
      const index = safePrev.findIndex((item) => item.symbol === priceUpdate.latest?.symbol);
      if (index === -1) {
        return [
          ...safePrev,
          {
            symbol: priceUpdate.latest?.symbol,
            name: priceUpdate.latest?.symbol,
