            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Live Events: {priceUpdate.all.length}
            </Text>
          </Row>
        </Card>
        {!hasStocks ? (
          <Alert variant="info" title="No stocks to display">
            Waiting for initial stock data or live updates.
          </Alert>
        ) : (
          <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
            {(stocksState || []).map((stock, index) => {
              const changeValue = stock.change ?? 0;
              const changePercentValue = stock.changePercent ?? 0;
              const isPositive = changeValue >= 0;
              const arrow = isPositive ? '▲' : '▼';
              const borderColor = isPositive ? 'var(--ggui-color-success)' : 'var(--ggui-color-error)';
              const changeColor = isPositive ? 'var(--ggui-color-success)' : 'var(--ggui-color-error)';
              return (
                <Card
