      setStep(step + 1);
      setTouched(false);
    }
  }, [step, canProceed]);

  const prevStep = useCallback(() => {
    if (step > 1) {
      setStep(step - 1);
      setTouched(false);
    }
  }, [step]);

  const submit = useCallback(() => {
    if (!step1Valid || !step2Valid) return;
    complete({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  }, [complete, step1Valid, step2Valid, name, email, avatar, role, emailNotifications, theme]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Heading level={3}>Onboarding Wizard</Heading>
              <Badge variant="primary">Step {step} of 3</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" />
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              Complete your profile in three quick steps.
            </Text>
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm" radius="lg">
          <Box
            style={{
              animation: 'ggui-fadeIn 200ms ease-out',
            }}
          >
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Profile Setup</Heading>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  error={touched && name.trim().length === 0 ? 'Name is required' : undefined}
                  placeholder="Enter your full name"
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  error={touched && !emailValid ? 'Enter a valid email address' : undefined}
                  placeholder="you@example.com"
                />
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label">Choose an avatar</Text>
                  <Row gap="var(--ggui-spacing-2)" wrap>
                    {(props.avatarOptions.length > 0 ? props.avatarOptions : ['😀', '🚀', '🎨', '📈']).slice(0, 4).map((option) => (
                      <Card
                        key={option}
                        as={Clickable}
                        onClick={() => setAvatar(option)}
                        padding="var(--ggui-spacing-3)"
                        border
                        radius="md"
                        shadow="none"
                        style={{
                          borderColor: avatar === option ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)',
                          background: avatar === option ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                          minWidth: '56px',
                          textAlign: 'center',
                        }}
                      >
                        <Text size="2xl" is="span">{option}</Text>
                      </Card>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Preferences</Heading>
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  placeholder="Select your role"
                  options={(props.roleOptions.length > 0 ? props.roleOptions : ['Developer', 'Designer', 'Manager', 'Other']).map((r) => ({ value: r, label: r }))}
                  error={touched && role.trim().length === 0 ? 'Role is required' : undefined}
                  required
                />
                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                />
                <Toggle
                  label={theme === 'dark' ? 'Theme: Dark' : 'Theme: Light'}
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Review & Confirm</Heading>
                <Alert variant="info" title="Please review your details">
                  You can go back to edit any field before completing setup.
                </Alert>
                <Card padding="var(--ggui-spacing-4)" shadow="none" radius="md">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Row justify="between"><Text variant="label">Name</Text><Text>{name || '-'}</Text></Row>
                    <Row justify="between"><Text variant="label">Email</Text><Text>{email || '-'}</Text></Row>
                    <Row justify="between"><Text variant="label">Avatar</Text><Text>{avatar || '-'}</Text></Row>
                    <Row justify="between"><Text variant="label">Role</Text><Text>{role || '-'}</Text></Row>
                    <Row justify="between"><Text variant="label">Email Notifications</Text><Text>{emailNotifications ? 'On' : 'Off'}</Text></Row>
                    <Row justify="between"><Text variant="label">Theme</Text><Text>{theme}</Text></Row>
                  </Stack>
                </Card>
              </Stack>
            )}
          </Box>

          <Divider margin="var(--ggui-spacing-4)" />
          <Row justify="between" align="center">
            <Button variant="outline" onClick={prevStep} disabled={step === 1}>
              Back
            </Button>
            {step < 3 ? (
              <Button variant="primary" onClick={nextStep} disabled={!canProceed}>
                Next
              </Button>
            ) : (
              <Row gap="var(--ggui-spacing-2)">
                <Button variant="outline" onClick={prevStep}>Go Back</Button>
                <Button variant="primary" onClick={submit}>Complete Setup</Button>
              </Row>
            )}
          </Row>
        </Card>
      </Stack>
    </Container>

  );
}
